INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','제85차 조찬간담회 언론보도','Conference allshowTV English ETstudio 검색 경제·금융 전자·모빌리티 통신·미디어·게임 소재·부품 AI·SW·보안 산업·에너지·환경 플랫폼·유통 헬스케어·벤처 정치 전국 국제 과학기술·디','Conference allshowTV English ETstudio 검색 경제·금융 전자·모빌리티 통신·미디어·게임 소재·부품 AI·SW·보안 산업·에너지·환경 플랫폼·유통 헬스케어·벤처 정치 전국 국제 과학기술·디지털로 여는 새로운 대한민국 발행일 : 2024-02-15 15:51 동북아 공동체 I CT 포럼 조찬간담회가 15일 서울 중구 프레스센터에서 열렸다. 이종호 과학기술정보통신부 장관이 ''과학기술·디지털로 여는 새로운 대한민국''을 주제로 발표하고 있다.','2024-03-06','','','',1,51,'2024-03-06 00:00:00','2024-03-06 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','제84차 조찬간담회 언론보도','김형진 세종텔레콤 회장 “정도·인재·창조경영으로 사회발전 이바지”…동북아공동체ICT포럼 발행일 : 2023-12-02 20:59 지면 : 2023-12-04 17면 <동북아 공동체 ICT포럼 제84회 조찬 간담회가 ','김형진 세종텔레콤 회장 “정도·인재·창조경영으로 사회발전 이바지”…동북아공동체ICT포럼 발행일 : 2023-12-02 20:59 지면 : 2023-12-04 17면 <동북아 공동체 ICT포럼 제84회 조찬 간담회가 서울 강남구 삼정호텔에서 열렸다. 김형진 세종텔레콤 회장이 ''세종의 법계''를 주제로 강연하고 있다. 이동근기자 foto@etnews.com> 김형진 세종텔레콤 회장이 기업 운영에 동양철학을 접목한 공리주의 경영의 중요성을 강조했다. 사회적 갈등과 저성장 한계를 극복하기 위해서는 정도·인재·창조경영 중심의 정보통신기술(I CT ) 혁신을 통해 사회에 이바지하는 기업으로 거듭나야 한다는 설명이다. 김 회장은 최근 삼정호텔에서 열린 동북아공동체ICT포럼 제84차 조찬 간담회에서 ''세종의 법계:공부경영''을 주제로 강연했다. 김 회장은 “채권업부터 시작해 증권업, 통신업 등 다양한 사업에 뛰어들고 우여곡절을 겪으면서 매출 3000억원 규모 정보통신기업을 키워냈다”면서 “사회 공익에 기여하는 기업을 만들고자 동양의 세계관을 경영에 접목, 공리주의 경영에 관심을 키웠다”고 말했다. 세종텔레콤은 홍익인간 정신을 계승하고자 ''홍승기업''이란 사명으로 창업했다. 세종대왕의 창조와 혁신 자세를 기업 정신으로 받아들이기 위해 사명을 ''세종''으로 변경했다. 경영 철학도 창조와 공유를 기반으로 한 나눔정신이다. 현재까지 130억원을 사회에 기부한 것도 이 때문이다. 그는 경영원칙으로 정도경영, 인재경영, 창조경영을 꼽았다. 김 회장은 주역의 선천팔괘, 후천팔괘를 인용해 욕심내지 않는 정도경영 정신을 강조했다. 유무선 통신뿐 아니라 블록체인, 전기공사, ICT솔루션, 보안 등 사업 모델을 다각화하는 창조정신에 대해 설명했다. 김 회장은 “음양오행의 기업철학을 기반으로 회사의 핵심가치를 수기치인(修己治人), 부정거사(扶正祛邪), 자강불식(自强不息)에 두고 있다”면서 “이는 자율을 기반으로 집단지성을 발휘하는 기본 원동력이 된다”고 덧붙였다. <동북아 공동체 ICT포럼 제84회 조찬 간담회가 1일 서울 강남구 삼정호텔에서 열렸다. 김형진 세종텔레콤 회장이 ''세종의 법계''를 주제로 강연하고 있다. 이동근기자 foto@etnews.com> 그는 세계 경제 불확실성과 위기가 커질수록 바른경영 자세가 필요하다고 강조했다. 김 회장은 “자본주의는 경제성장을 통해 배고픈 문제를 해결해줬지만 불평등에 따른 사회 불안요인도 가중했다”면서 “민주주의 제도를 기반으로 경제적가치와 사회적가치를 중시하는 이해관계자 자본주의를 기업정신으로 함양해야 사회적 갈등 해소와 경제 성장을 다 잡을 수 있다”고 말했다. 이날 포럼을 주관한 석호익 동북아공동체ICT포럼 회장은 “정보기술(IT) 선진국을 이끈 주역인 오명 전 부총리 겸 과학기술부 장관과 윤동윤 전 체신부 장관, 주호영 의원과 강연을 맡아준 김형진 세종텔레콤 회장 등 모든 참석자들에게 감사드린다”면서 “포럼이 인공지능(AI) 시대 미래에 대응하는 핵심 역할을 해 나갈 것”이라고 말했다. 박준호 기자 junho@etnews.com','2024-01-04','','','',1,50,'2024-01-04 00:00:00','2024-01-04 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','2023년 제2기 "초거대AI활용 생성테크 교육" 실시','2023년 제2기 "초거대AI활용 생성테크 교육" 실시','본 게시물의 원문은 이미지로 게시되어 있습니다. 자세한 내용은 첨부파일 또는 원문을 참고하시기 바랍니다.','2023-11-09','','','',1,49,'2023-11-09 00:00:00','2023-11-09 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','2023년 제1기 "초거대AI활용 생성테크 교육" 수료식 언론보도','제1기 초거대AI활용 생성테크 전문교육생 42명 배출 발행일 : 2023-07-23 21:30 지면 : 2023-07-24 18면 <오명 전 부총리(왼쪽 네번째부터)와 석호일 동북아공동체ICT포럼 회장(전 KT 부회','제1기 초거대AI활용 생성테크 전문교육생 42명 배출 발행일 : 2023-07-23 21:30 지면 : 2023-07-24 18면 <오명 전 부총리(왼쪽 네번째부터)와 석호일 동북아공동체ICT포럼 회장(전 KT 부회장)이 제1기 초거대AI 활용 생성테크 전문교육 수료생과 기념촬영했다.> 동북아공동체I CT 포럼은 지난 20일 서울시 성내동 피스센터에서 석호익 포럼 회장, 오명 전 부총리, 전진우 원우회 회장 등 50여명이 참석한 가운데 제1기 ''초거대AI활용 생성테크 교육'' 수료식을 개최했다. 초거대AI활용 생성테크 교육은 주1회 총 12회 초거대AI 관련 전문 강의로 구성됐다. 한국IT전문가협회, 한국정보통신공사협회, 한국전파진흥협회, 한국디지털컨버전스협회의 후원과 전자신문의 협찬으로 약 3개월간 진행됐다. 석호익 회장은 수료식 축사에서 “앞으로의 세계는 챗GPT를 잘 활용할줄 아는 사람이 챗GPT를 잘 활용할 줄 모르는 사람을 대체할 것”이라며 “인터넷을 사용할 줄 모르면 경쟁에서 낙오되듯이 챗GPT를 잘 배워 정보화 혁명에 이은 AI혁명에 앞장서야 한다”고 강조했다. 교육은 지난 5월4일 장병탁 서울대AI연구원 교수의 ''초거대AI 챗GPT : 현황,전망, 대응전략''을 1회 주제강의로 시작했다. 마이크로소프트, 네이버, 카카오의 개방형AI소개와 사업방향 제시, KT,LG유플러스의 챗GPT 관심 분야 및 활용 준비 상황 등을 다뤘다. 챗GPT 활용 글쓰기, 그림그리기, 분야별 프롬프트 활용 방법, 생산성 극대화 방안과 다양한 AI체험해보기 프로그램으로 구성해 12차례 진행했다. 수료식에서는 오명 전 부총리가 참석해 축사했다. 정보통신기술(ICT) 업계 협회 임원과 교수, 기업인 등 총 42명이 수료했다. 2기 교육은 9월 19일부터 재개된다. 박지성 기자 jisung@etnews.com','2023-07-24','','','',1,48,'2023-07-24 00:00:00','2023-07-24 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','제82회 조찬간담회 언론보도','박원곤 통일학연구원장 “美 대통령 바뀌어도 기조 안 바뀐다…北, 결국 협상 테이블 나올 것” 발행일 : 2023-07-04 10:33 지면 : 2023-07-05 6면 <동북아공동체ICT포럼 조찬간담회가 4일 서울 ','박원곤 통일학연구원장 “美 대통령 바뀌어도 기조 안 바뀐다…北, 결국 협상 테이블 나올 것” 발행일 : 2023-07-04 10:33 지면 : 2023-07-05 6면 <동북아공동체ICT포럼 조찬간담회가 4일 서울 역삼동 삼정호텔에서 열렸다. 박원곤 이대 교수가 ''급변하는 국제정세와 한반도''를 주제로 발표하고 있다. 박지호기자 jihopress@etnews.com> 미·중 갈등과 우크라이나·러시아 전쟁 등 급변하는 세계 질서를 기반으로 북한을 해석해야 한다는 목소리가 나왔다. 박원곤 이화여자대학교 통일학연구원장은 대통령이 바뀌어도 미국의 현재 기조는 변화하지 않을 것이라며 북한이 결국 협상을 하게 될 것이라고 전망했다. 박 원장은 4일 서울 강남구 삼정호텔에서 열린 동북아공동체I CT 포럼 제82차 조찬간담회에서 “북한은 세계 변화에 가장 민감하게 반응하는 국가”라며 “김정은이 북한의 경제성장을 이끌고 싶어하지만 비핵화 협상 테이블에 나오고 제재를 해제하지 않는 한 한계가 있다. 북한은 경제적인 이유 등을 포함해 결국 협상 테이블에 나올 것”이라고 말했다. 박 원장은 현재 세계의 구도를 ''신냉전''으로 분석하는 것에 동의하지 않았다. 박 원장은 “냉전 시대의 가장 큰 특징은 미국·소련 중심의 독립된 경제권”이라며 “중국을 빼고 세계 경제를 이끌어 갈 수 없다. 미국과 중국의 갈등이 격화되더라도 변화는 없을 것”이라고 해석했다. 그러면서도 한국의 선택지는 사실상 결정돼 있다는 취지로 언급했다. 박 원장은 “미국 중심의 일극 체제 종식과 다극 체제로의 변화로 이어지다가 이제는 중국이 정점(China peak)을 찍었다는 얘기가 나온다. 중국이 쇠퇴할 것이라는 얘기가 학계에서 많이 제기되고 있다”며 “한국은 미국·중국과 다 잘 지내야 하지만, 만약 하나를 선택해야 하는 상황으로 몰린다면 중국 정점론을 살펴봐야 한다”고 조언했다. 우크라이나·러시아 전쟁이 준 시사점도 언급했다. 박 원장은 “북·중·러 관계는 역사적으로 보면 서로를 절대로 믿지 않는다. 현재 이들은 미국이라는 공통의 적에 대항하기 위해 힘을 합치는 편의에 의한 결합(Marriage of Convenience)”이라고 분석했다. 중국을 다루는 미국의 방식에도 변화가 있다는게 박 원장의 설명이다. 그는 “미국은 맞춤형·소규모·의제별 협의체를 설립하는 방식으로 중국을 견제하고 있다. 이 속에서 미국은 한국이 두 가지 선택지 중에 골라야 하는 방식을 사용하고 있다. 거칠게 말하면 동맹줄 세우기”라면서도 “미국은 중국을 완전히 봉쇄하거나 배제할 생각은 없다”고 분석했다. 아울러 미국 인플레이션 감축법(IRA) 등을 두고는 미국 대통령이 바뀌더라도 기조가 유지될 것이라고 예상했다. 박 원장은 “자체 역량 강화, 미국 경쟁력을 위한 투자·혁신, 민주주의 복원이 IRA 등을 통해 나타나고 있다. 중국이 지배하는 핵심 물품과 자원에 대한 의존도를 줄이고 급격한 탈동조와 부과한 경제 충격을 완화하기 위해 다양한 선택지를 고민하고 있다”고 설명했다. 최기창 기자 mobydic@etnews.com','2023-07-05','','','',1,47,'2023-07-05 00:00:00','2023-07-05 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','제81회 조찬간담회 언론보도','고진 디플정위원장 "국민 불편함 줄이는 혁신 정부 구현" 발행일 : 2023-04-26 11:16 지면 : 2023-04-27 16면 <동북아공동체ICT포럼 제81차 조찬간담회가 26일 서울 강남구 삼정호텔에서 열렸','고진 디플정위원장 "국민 불편함 줄이는 혁신 정부 구현" 발행일 : 2023-04-26 11:16 지면 : 2023-04-27 16면 <동북아공동체ICT포럼 제81차 조찬간담회가 26일 서울 강남구 삼정호텔에서 열렸다. 고진 디지털플랫폼 정부위원회 위원장이 디지털플랫폼정부 실현계획을 주제로 발표하고 있다. 김민수기자 mskim@etnews.com> “정부가 알아서 국민 맞춤형 혜택을 안내하고 서류제출로 허비하는 시간을 줄이는 등 국민이 일상에서 느끼는 불편함을 줄이는 디지털정부플랫폼을 구현하는데 주력하겠습니다.” 고진 디지털플랫폼정부위원회 위원장은 26일 서울 삼정호텔에서 ''동북아공동체 I CT 포럼'' 주최 조찬간담회에 참석해 정부 디지털플랫폼정부 실현계획을 발표했다. 고 위원장은 “청년 실업률이 7%인 상황에서 청년이 누릴 수 있는 지원 프로그램은 4000개 이상이지만 취업 준비 등으로 바쁘거나 몰라서 혜택을 놓치는 경우가 발생한다”면서 “청년 정책뿐만 아니라 부모수당, 국가 장학금, 실업수당 등 국민에게 맞는 혜택을 정부가 알아서 전달하는 체계를 만들겠다”고 소개했다. 디지털플랫폼정부(디플정)위원회는 이 같은 내용을 담은 디플정 실현전략을 최근 공개했다. 관공서 방문, 첨부서류, 대기시간 등을 없애 국민 불편을 해결하고 부처간 칸막이 허물기 등 정부 협업과 혁신을 강화한다. 새로운 산업과 비즈니스 기회를 창출하는 등 기업 성장도 지원한다. 고 위원장은 “디플정 프로젝트를 통해 국민 시간과 비용 절감뿐만 아니라 신속·유연한 정부 구현, 안전한 데이터 활용 등 다양한 가치를 만들겠다”면서 “위원회가 중심이 돼 디플정 범정부 확산과 지속가능한 정책을 추진하겠다”고 강조했다. 김지선기자 river@etnews.com https://www.etnews.com/20230426000139','2023-05-18','','','',1,46,'2023-05-18 00:00:00','2023-05-18 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','통일ICT전문가 아카데미 원우회 세미나 언론보도','통일ICT전문가 원우회, 3년 만에 세미나 개최 발행일 : 2023-04-14 15:44 지면 : 2023-04-17 27면 <통일ICT전문가 전체 원우회는 13일 세미나 겸 인사회를 개최했다(사진=통일ICT전문가 ','통일ICT전문가 원우회, 3년 만에 세미나 개최 발행일 : 2023-04-14 15:44 지면 : 2023-04-17 27면 <통일ICT전문가 전체 원우회는 13일 세미나 겸 인사회를 개최했다(사진=통일ICT전문가 전체 원우회)> 통일I CT 전문가 원우회는 코로나19로 3년간 중단했던 세미나 겸 인사회를 회원 40명이 참석한 가운데 개최했다. 세미나에서는 북한 이과대학 졸업 후 중앙당 과학교육부에 근무했던 탈북자 장혁씨를 연사로 초청해 ''북한 정보통신 기술현황과 미래''를 주제로 한 발표를 듣고 질의응답 시간을 가졌다. 통일ICT전문가 교육 수료자로 구성된 통일ICT전문가 원우회는 앞으로도 세미나 개최 및 등산 행사 등을 통해 남북한 ICT교류협력 방안을 모색하고 회원간 유대관계를 도모할 계획이다. 통일ICT전문가아카데미 과정은 남북간 ICT 교류·협력에 대비해 주 1회 2시간씩 총 10번의 전문 강의를 받고 북중 접경지역을 체험하는 과정이다. 동북아공동체ICT포럼에서 전자신문 후원으로 매년 진행하는 북한 교육 프로그램이다. 송윤섭기자 sys@etnews.com https://www.etnews.com/20230414000233','2023-05-18','','','',1,45,'2023-05-18 00:00:00','2023-05-18 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','제80회 조찬간담회 언론보도','제80회 동북아공동체ICT포럼 발행일 : 2023-02-22 14:33 제80회 동북아공동체I CT 포럼 조찬간담회가 22일 서울 중구 프레스센터에서 열렸다. 권영세 통일부 장관이 ''최근 한반도 정세 및 윤석열 정부','제80회 동북아공동체ICT포럼 발행일 : 2023-02-22 14:33 제80회 동북아공동체I CT 포럼 조찬간담회가 22일 서울 중구 프레스센터에서 열렸다. 권영세 통일부 장관이 ''최근 한반도 정세 및 윤석열 정부의 통일·대북 정책''을 주제로 발표하고 있다. <권영세 통일부 장관(앞줄 왼쪽 여섯번째부터), 오명 전 과학기술부오명 전 과학기술 부총리, 석호익 동북아공동체ICT포럼 회장을 비롯한 관계자들이 기념촬영을 하고 있다.> 김민수기자 mskim@etnews.com https://www.etnews.com/20230222000194','2023-05-18','','','',1,44,'2023-05-18 00:00:00','2023-05-18 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','제 79회 조찬간담회 언론보도','김병준 ''진보와 보수를 넘어'' - 전자신문 (etnews.com) 김병준, "계속되는 정권 실패 국가시스템이 문제" - 전자신문 (etnews.com)','김병준 ''진보와 보수를 넘어'' - 전자신문 (etnews.com) 김병준, "계속되는 정권 실패 국가시스템이 문제" - 전자신문 (etnews.com)','2022-12-08','','','',1,43,'2022-12-08 00:00:00','2022-12-08 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','제68회 정보통신의 날 기념식 포상공고 안내','제68회 정보통신의 날 기념식 포상공고 안내','본 게시물의 원문은 이미지로 게시되어 있습니다. 자세한 내용은 첨부파일 또는 원문을 참고하시기 바랍니다.','2022-11-09','','(붙임4) 정보통신의 날 기념식 포상공고 포스터.jpg [850KB]','',1,42,'2022-11-09 00:00:00','2022-11-09 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','제78회 조찬간담회 보도자료','과학기술정보통신부가 국가 생존을 좌우할 전략기술 10개를 선정하고 구체적인 로드맵을 구축한다. 우주·항공, 양자, 6G 등 주요 기술을 선제 확보하고 집중투자해 ''팍스 테크니카'' 시대에 대응해 글로벌 우위를 선점하겠','과학기술정보통신부가 국가 생존을 좌우할 전략기술 10개를 선정하고 구체적인 로드맵을 구축한다. 우주·항공, 양자, 6G 등 주요 기술을 선제 확보하고 집중투자해 ''팍스 테크니카'' 시대에 대응해 글로벌 우위를 선점하겠다는 전략이다. 이종호 과기정통부 장관은 2일 서울 역삼동 삼정호텔에서 열린 ''동북아공동체 ICT 포럼'' 조찬 간담회에서 “장기적으로 국가 경제와 사회발전을 견인할 전략기술과 신산업을 선점하고자 한다”며 “범부처 합동 프로젝트인 초격차 국가전략기술 프로젝트를 통해 5~7년 내에 각 분야에서 가시적인 성과가 창출될 수 있도록 하겠다”고 말했다. 과기정통부는 우주항공·인공지능(AI)·6G·반도체·첨단바이오·이차전지·첨단로봇·양자·사이버보안·수소 등 10개 내외를 전략기술로 선정할 방침이다. 이 장관은 “화합물 반도체·AI반도체 등 연구개발(R&D)에 향후 5년간 1조원 이상 예산을 투자할 것”이라며 “양자 분야에서는 2026년까지 50큐비트급 양자컴퓨터 및 양자인터넷을 개발하겠다”고 말했다. 이어 “뉴스페이스 산업 활성화를 위해 위성영상 분석 활용 등 초소형 위성을 활용한 서비스기업을 지원하고, 항공우주청 신설 등 선도형 거버넌스 구축을 추진하겠다”고 덧붙였다. 과기정통부는 차세대 네트워크 산업 육성을 위해 오픈랜 과 위성통신 등 6G 관련 기술도 선도적으로 확보할 계획이다. 전략기술을 체계적으로 지원하기 위한 ''국가전략기술육성특별법''도 연내 추진할 계획이다. 기존에 부처별로 진행하던 예산을 플랫폼별로 조정하는 횡적 체계를 수립해 R&D를 위한 효율적인 예산 배분을 꾀한다. 우선순위를 고려해 민관이 공유할 수 있는 기술개발 목표를 수립하고, 120개사 최고기술경영자(CTO)가 참여하는 민간R&D 협의체를 통해 실질적인 투자연계와 상용화를 유도할 방침이다. 기술개발과 산업 발전의 핵심은 결국 인력이라는 접근 하에 기술혁신 주도형 인재를 양성한다. 이 장관은 “단기적으로는 민간수요 맞춤형 인재를 키우고, 장기적으로는 최고급 전문형 인재를 양성하겠다”고 말했다. 과기정통부는 계약정원제와 패스트러닝 등 기업 수요에 신속히 대응할 수 있는 제도를 마련하고, 10년 이상 한 분야의 도전적 연구에 전념할 수 있는 한우물 파기 등을 지원한다는 방침이다. 이 장관은 “초격차 전략기술 선점과 디지털 전환을 바탕으로 경제와 사회의 변혁을 이끌 수 있는 국가 혁신을 주도하겠다”고 강조했다.','2022-09-08','','','',1,41,'2022-09-08 00:00:00','2022-09-08 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','본 포럼의 77차 조찬간담회(7월 13일 수요일)에서','김황식 전 국무총리가 우리나라 정치의 문제로 대화와 타협 부족을 꼽았다. 김 전 총리는 한국 정치의 롤모델로 독일을 제시한 뒤 제왕적 대통령제를 극복하기 위한 개헌이 필요하다고 강조했다. 김 전 총리는 13일 서울 ','김황식 전 국무총리가 우리나라 정치의 문제로 대화와 타협 부족을 꼽았다. 김 전 총리는 한국 정치의 롤모델로 독일을 제시한 뒤 제왕적 대통령제를 극복하기 위한 개헌이 필요하다고 강조했다. 김 전 총리는 13일 서울 강남구 역삼동에서 열린 동북아공동체ICT포럼 조찬간담회에서 “독일은 2차 대전 당시 나치 정권의 만행을 일으킨 전범 국가였다. 이 때문에 국토도 분단됐다”며 “하지만 독일은 참혹한 역사의 비극을 극복했다. 독일의 정치를 배워야 한다”고 말했다. 김 전 총리는 독일의 정치 제도가 민주주의를 제대로 반영하고 있다고 평가했다. 김 전 총리는 “독일은 절반이 비례대표”라며 “의석 배분을 정당투표 비율에 따라 배분한다. 결국 한 정당이 과반을 달성하기 힘든 구조”라고 설명했다. 김 전 총리는 독일 정치에 대화·타협이 자리 잡은 이유로 연정을 꼽았다. 김 전 총리는 “과반을 달성해야 집권을 할 수 있기에 자연스레 연립 정부가 구성된다. 총리와 장관 등을 배분하는 과정에서 대화와 타협을 할 수밖에 없다”고 언급했다. 또 “정부를 같이 구성하려면 선거 공약을 하나로 합치는 협상도 하게 된다. 독일은 대화와 타협을 바탕으로 한 연정을 통해 안정된 의석을 확보한 뒤 협상한 내용에 따라 국정을 운영하는 시스템”이라며 “늘 대화와 타협으로 풀어가는 정치 풍토가 조성된 이유”라고 설명했다 김 전 총리는 독일 역대 총리의 리더십도 강조했다. 김 전 총리는 “쿠르트 키징거 총리는 우파와 좌파의 대연정을 이뤄낸 인물”이라고 평가했다. 아울러 “나치에 부역했던 키징거와 나치에 저항했던 빌리 브란트가 함께 정권을 구성한 대연정이 일어났다. 키징거 총리의 별명은 걸어 다니는 중재위원회였다”며 대화·타협의 중요성을 재차 강조했다. 또 “이후 소연정을 통해 총리가 된 빌리 브란트는 냉전을 풀고 동구권 국가와 교류·협력하는 소위 포용정책을 펼쳤다. 당시 2차 세계대전 이후 폴란드로 넘어간 땅을 포기하겠다는 말과 함께 독일 국민들의 반대를 설득했다”고 말했다. 역대 독일 총리의 덕목으로 희생정신을 꼽기도 했다. 김 전 총리는 “독일의 총리들은 자기 철학과 소신을 가지고 국민들을 이끌었다. 총리직에서 쫓겨나고 선거에서 실패해도 자기희생을 기꺼이 했다. 그래서 오늘날의 독일이 있을 수 있었다”고 했다. 김 전 총리는 현재 한국 정치에 대화와 타협이 사라졌다고 진단했다. 사실상 한국 정치가 양당제로 운영되고 있기 때문이다. 김 전 총리는 “한국 정치는 대립과 갈등이 더욱 심해지고 있다. 우리도 대화와 타협을 통한 정치를 하는 게 바람직하다”고 설명했다. 한국 정치가 갈등으로 치닫는 가장 큰 원인으로는 제도를 꼽았다. 김 전 총리는 “통합을 위해 애쓰는 훌륭한 대통령이 나오면 현재의 대통령제에서도 좋은 결과를 낼 수 있다”면서도 “그러나 제도가 이렇게 마련된 이상 제왕적 대통령제를 바탕으로 한 권력 집중과 권력 독점이 일어날 수밖에 없다”고 말했다. 다만 윤석열 정부에 대한 평가는 유보했다. 김 전 총리는 “(윤 정부가) 출범한 지 얼마 되지 않았다. 평가하기엔 다소 이른 시점”이라고 언급했다. 최기창기자 mobydic@etnews.com','2022-07-14','','','',1,40,'2022-07-14 00:00:00','2022-07-14 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','데이터스트림즈, 데이터거버넌스 기술과 경험으로 데이터 패브릭 전략 펼친다.','이 본문은 전자신문 2021.03.02일자 기사입니다. 자세한 내용은 https://www.etnews.com/20210302000206 를 타고 확인하시길 바랍니다. 데이터스트림즈, 데이터거버넌스 기술과 경험으로 ','이 본문은 전자신문 2021.03.02일자 기사입니다. 자세한 내용은 https://www.etnews.com/20210302000206 를 타고 확인하시길 바랍니다. 데이터스트림즈, 데이터거버넌스 기술과 경험으로 데이터 패브릭 전략 펼친다.','2021-03-03','','','',1,39,'2021-03-03 00:00:00','2021-03-03 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','[(주)데이터스트림즈] 사외 Newsletter 12월호','[(주)데이터스트림즈] 사외 Newsletter 12월호','본 게시물의 원문은 이미지로 게시되어 있습니다. 자세한 내용은 첨부파일 또는 원문을 참고하시기 바랍니다.','2020-12-21','','','',1,38,'2020-12-21 00:00:00','2020-12-21 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','(주)데이터스트림즈, 2020 NH농협은행 시니어 바둑리그 데이터스트림즈팀 창단','포럼기관회원사인 (주)데이터스트림즈가 5년의 리그역사를 가진 NH농협은행 시니어바둑리그에 서울 연고의 <데이터스트림즈>팀을 결성했습니다. 시니어 바둑리그에서 좋은 성적을 거두는 것뿐만 아니라, 선진 데이터 처리기술을','포럼기관회원사인 (주)데이터스트림즈가 5년의 리그역사를 가진 NH농협은행 시니어바둑리그에 서울 연고의 <데이터스트림즈>팀을 결성했습니다. 시니어 바둑리그에서 좋은 성적을 거두는 것뿐만 아니라, 선진 데이터 처리기술을 접목해 대한민국 바둑계의 발전과 대한민국형 알파고를 탄생하는데 기여하는 성과 거두시길 바랍니다. 축하합니다. 아래는 창단소식입니다.','2020-07-13','','','',1,37,'2020-07-13 00:00:00','2020-07-13 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','이승용 KT 전무(본 포럼 부회장), 스마트미디어산업진흥협회 회장 취임','우리 포럼의 부회장이자, KT 전무이신 이승용 님이 스마트미디어산업진흥협회의 회장으로 취임하심을 축하드립니다. 아래는 관련 기사 본문입니다. --- 스마트미디어산업진흥협회는 8일 정기총회에서 제6대 회장으로 이승용 ','우리 포럼의 부회장이자, KT 전무이신 이승용 님이 스마트미디어산업진흥협회의 회장으로 취임하심을 축하드립니다. 아래는 관련 기사 본문입니다. --- 스마트미디어산업진흥협회는 8일 정기총회에서 제6대 회장으로 이승용 KT 전무( CR 1실장)를 선임했다. 신임 이 회장은 “5G를 기반으로 한 인공지능(AI), 빅데이터 , 사물인터넷 ( IoT ), 가상현실 ( VR )·증강현실(AR) 등이 주도해 모든 산업이 융합되는 4차 산업혁명 시대가 도래하고 있다”며 “ 온라인동영상서비스 ( OTT )와 VR·AR, 디지털사이니지 등 스마트미디어 분야가 성장할 것으로 기대한다”고 말했다. 그는 “회원사간 협업과 협회 역량을 강화해 스마트미디어 산업을 발전시켜 나가겠다”고 덧붙였다. 스마트미디어산업진흥협회는 스마트미디어 산업 진흥을 위해 2010년 설립된 과학기술정보통신부 산하 비영리 사단법인이다. 박지성기자 jisung@etnews.com 출처: https://www.etnews.com/20200408000237','2020-04-09','','','',1,36,'2020-04-09 00:00:00','2020-04-09 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','권태일 빅썬시스템즈 대표, 전자신문 오늘의 CEO 선정','본 포럼 기업 회원사인 빅썬시스템즈 권태일 대표께서 전자신문의 오늘의 CEO란에 소개되었습니다 . 아래는 2020 년 4 월 6 일 전자신문 기사입니다 . [본문] “공공와이파이의 편의성을 개선, 대중화에 앞장서겠습','본 포럼 기업 회원사인 빅썬시스템즈 권태일 대표께서 전자신문의 오늘의 CEO란에 소개되었습니다 . 아래는 2020 년 4 월 6 일 전자신문 기사입니다 . [본문] “공공와이파이의 편의성을 개선, 대중화에 앞장서겠습니다.” 권태일 빅썬시스템즈 대표는 6일 “정부가 추진하는 공공와이파이 사업이 성공할 수 있도록 적극 뒷받침하겠다”며 이같이 밝혔다. 빅썬시스템즈는 공공와이파이 전문 기업이다. 권 대표가 2011년에 설립했다. 미국 와이파이 장비 업체 지러스( XIRRUS )의 파트너 회사로, 와이파이 송수신장치( AP )를 국내에 독점 판매하고 있다. 지금까지 AP 6만여대를 국내에 판매했다. 권 대표는 “코레일 ·SRT 가 운영하는 국내 모든 열차에 지러스 AP 가 설치됐다”면서 “버스와 공공기관으로 사업 영역을 확장하고 있다”고 설명했다. 주력 사업은 AP 설계와 구축이다. AP 간 간섭 현상을 없애면서도 효율은 극대화하는 AP 설치 최적 장소를 찾아내는 설계 노하우를 확보했다. 공간 내 창문 개수와 벽 두께·재질 등을 종합 고려, AP 적정 수량도 계산한다. 이 같은 저력을 바탕으로 고성능·고용량 AP 시장도 석권했다. 대규모 행사장에 적합한 이동형 AP 를 선보였다. 동시 접속자 40~50명을 감당하는 일반 AP 보다 5~6배 많은 최대 300명을 수용한다. 지난 2018년 남북 정상회담이 열릴 당시 킨텍스 기자실에 설치했다. AP 10대를 국내외 기자 3000여명이 사용했다. AP 유지·보수 분야 경쟁력도 최고 수준이다. 권 대표는 “ AP 만 설치하고 유지·보수에는 소홀하다 보니 대외 환경 변화에 AP 가 오랜 시간 방치되는 사례가 허다하다”면서 “회사 인력 대부분을 유지·보수에 투입, 서비스 안정성을 유지하고 있다”고 말했다. 빅썬시스템즈는 부산역·목포역·수서역에 긴급 복구반을 운영하고 있다. 오작동 발생 시 협력업체와 곧바로 복구에 나설 수 있도록 시스템을 구축했다. 수서역에는 실시간 모니터링 시스템을 가동하고 있다. 권 대표는 “10년 가까이 와이파이 한 우물만 파 왔다”면서 “ AP 로 수집되는 다양한 정보를 바탕으로 와이파이 서비스 고도화 방안을 찾고 있다”고 전했다. 와이파이 시장 전망은 밝다. 정부, 지방자치단체에 이어 정치권도 공공와이파이 보급을 공약했다. 5세대(5G) 이동통신과 와이파이6(802.11 ax ) 일체형 단말기도 대중화를 앞두고 있다. 권 대표는 창업 이전에 미국 썬마이크로시스템즈에서 20년 동안 근무했다. 2010년 회사가 오라클로 합병된 직후 창업했다. 썬마이크로시스템즈보다 큰 기업을 만들겠다는 각오로 사명을 빅썬시스템즈로 정했다. 권 대표는 “와이파이는 이통사 롱텀에볼루션( LTE ) 및 5G 서비스와 상호보완 관계에 있다”면서 “단순히 무선 인터넷 서비스를 넘어 사물인터넷( IoT ) 기기 접속 통로로 폭넓게 활용될 것”이라고 기대감을 내비쳤다. 최종희기자 choijh @ etnews.com 출처: https://www.etnews.com/20200406000221','2020-04-07','','','',1,35,'2020-04-07 00:00:00','2020-04-07 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','정하문(유비덤) 연구소장 2018디지털이노베이션대상 수상','동북아공동체ICT포럼 골프회 회장이신 정하문 회장(원우회 2기)께서 큰 상을 수상하셨습니다. 축하드립니다. 아래는 10월 9일 한국일보에 게재된 관련 기사입니다. 물류 흐름 완벽 파악 볼트공정관리 시스템 [2018 ','동북아공동체ICT포럼 골프회 회장이신 정하문 회장(원우회 2기)께서 큰 상을 수상하셨습니다. 축하드립니다. 아래는 10월 9일 한국일보에 게재된 관련 기사입니다. 물류 흐름 완벽 파악 볼트공정관리 시스템 [2018 디지털이노베이션대상] 유비덤 유비덤은 ICT 에 투자할 자금이 넉넉하지 않고 인력도 부족해 어려움을 겪는 중소기업을 위해 MES 와 ERP 및 SCM 등을 구축해온 기업이다. 유비덤은 2016년부터 4차산업 혁명에 발맞춰 스마트 공장 운영에 맞는 BRAIN (볼트공정관리 시스템)과 SIMS (사출공정관리 시스템)을 자체 개발해 보급하고 있다. BRAIN 시스템은 POP ( Pont Of Product )를 완벽하게 지원하고 있으며 생산수량을 집계하는 서버가 없는 서버리스( Serverless ) 시스템과 생산현장에 공정이동표를 제외한 모든 종이가 없는 페이퍼리스( Paperless ) 시스템이 특징이다. 제조 Lot 추적이 정확하게 이뤄지기 때문에 물류 흐름을 완벽하게 파악할 수 있으며, 문제 발생 시 즉시 대응이 가능하다. 2017년말 기준 생산성 향상 30%, 매출신장 30%, 제조원가 절감 3% 효과를 나타냈다. SIMS 시스템은 사출기의 작동값( PLC 값)을 받아서 작업표준값과 비교해 오차 범위를 벗어나면 경고 메시지가 뜨고 설비는 자동으로 멈춘다. 현대/기아 자동차의 2차 벤더 품질기준인 SQ 에 최적화된 시스템으로 SQ 심사 대응에 효율적이다.','2018-10-15','','kakaotalk_20181015_141027763.jpg [186KB]','',1,34,'2018-10-15 00:00:00','2018-10-15 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','전자신문[기고] 송희경 국회의원 "온라인 사드 배치로 국가기간망과 전자장비 위험 대비"','본 포럼의 53차 조찬간담회(9월 28일 수요일)에서 "새로운 가치, 실행!"이라는 주제로 발표를 해주신 송희경의원님의 2017.9.7일 전자신문 기고입니다 원문보기: http://www.etnews.com/2017','본 포럼의 53차 조찬간담회(9월 28일 수요일)에서 "새로운 가치, 실행!"이라는 주제로 발표를 해주신 송희경의원님의 2017.9.7일 전자신문 기고입니다 원문보기: http://www.etnews.com/20170906000316 ----------------------------------------------------------------------------- 성동격서(聲東擊西)라 했다. 동쪽을 성나게 해 놓고 은밀하게 서쪽을 침범한다는 뜻이다. 북한의 6차 핵실험 충격이 가시기도 전에 북한 성동격서식 추가 도발을 걱정할 처지에 놓였다. 북한은 6차 핵실험에 앞서 각종 국가 기간망과 전자 장비를 셧다운시켜 도시를 마비시키는 초강력 전자기파( EMP ) 공격 가능성까지 거론했다. 북한이 핵실험과 미사일 실험 발사로 오프라인 위협 및 국가기간망과 사회안전망을 교란하고 파괴시키는 은밀한 고도의 사이버전 전개 가능성이 짙다. 북한은 1만명 규모의 사이버전략사령부를 보유하고 있다. 항공기와 자동차 위성위치확인시스템( GPS ) 교란 훈련을 강화하고 있는 것으로 알려졌다. 2009년에 청와대, 국방부, 국가정보원 등 주요 기관이 디도스( DDoS ) 공격을 받은 적이 있다. 2011년에는 농협 전산망 파괴, 2014년에는 한국수력원자력 전산망 해킹으로 원전 설계 도면이 유출됐다. 한반도 핵심 관계국은 발 빠르게 사이버 안보전 태세를 갖춰 나가고 있다. 사이버 안보 관련 기본법을 검토하며 사이버 공격에 능동 대응과 방어 태세 강화에 나선 것이다. 미국은 사이버사령부를 통합사령부로 격상시켰다. 일본은 사이버 공간에서 공격 대응을 담당하는 사이버보안 전략본부와 사이버보안센터를 대폭 강화했다. 영국은 국가 사이버보안 전략을 발표, 2020년까지 2조6600억원을 보안 예산으로 투입하기로 결정했다. 중국도 6월부터 사이버 단속이 강화된 사이버보안법을 시행했다. 이스라엘은 패트리엇과 아이언돔 등 물리 형태의 방어뿐만 아니라 5000명의 ''유닛 8200'' 보안 전문 부대를 양성하며 오프라인과 온라인 방어 체계를 구축했다. 오히려 한국은 이 같은 사이버보안 위기 상황을 대수롭지 않게 보는 듯하다. 정보통신망법, 국가사이버안전규정(대통령훈령) 등 부분 성격의 법규를 겨우 갖추고 있을 뿐 전략과 제도 기반이 매우 취약하다. 사이버테러방지법 역시 당리당략과 정쟁의 대상으로 변질돼 국회에서 수년째 제대로 된 논의조차 못하고 있는 실정이다. 여당은 과거에 주장한 ''민간 사찰'' 프레임만 고수하고 있다. 허술한 사이버보안은 국가 안보 뿐만 아니라 4차 산업혁명 시대 사회 전반을 무너뜨릴 수도 있다. 자율주행자동차 제어권이 탈취되면 운전자 안전이 위험해진다. 심장박동기, 인슐린 펌프 등 지능형 의료 해킹으로 환자의 생명이 위협받게 된다. 고도로 지능화된 스마트팩토리 네트워크 해킹은 핵심 산업 기밀 유출과 막대한 경제 손실을 초래하게 된다. 내년으로 다가온 평창 동계올림픽이 사이버테러의 타깃이 된다면 그야말로 치명타다. 사이버보안은 이 시대 국가 안보의 중요한 축이다. 국가 차원의 사이버보안 전략 수립을 미뤄서는 안 된다. 정부는 하루 빨리 지능형 통합 위기관리시스템을 선제 구축, 사이버 위협에 대비해야 한다. 국가 제1의 책무는 국민 안전과 생명 보호다. 북한의 오프라인 미사일 공격에 대응하기 위한 방어 수단으로 고고도미사일방어체계( THAAD ·사드) 배치가 필요하듯 사이버 정보전과 4차 산업혁명으로 기폭된 새로운 위험을 방어하려면 ''온라인 사드''가 필요하다. 지금이 바로 사이버테러방지법 제정에 조속히 나서야 할 골든타임이다. 송희경 자유한국당 국회의원(국회 4차산업혁명포럼 공동대표)','2017-09-07','','크기변환_온라인_사드_배치로_국가기간망_테러_대비해야_001.jpg [507KB]','',1,33,'2017-09-07 00:00:00','2017-09-07 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','남북협회 9월 뉴스레터','남북협회 9월 뉴스레터입니다. [남북협회뉴스레터 9월호] 북한의 시장화를 촉진하는 남북경협 보내기 미리보기 임시저장 내게쓰기 접기/펴기 새창으로 쓰기 첨부파일','남북협회 9월 뉴스레터입니다. [남북협회뉴스레터 9월호] 북한의 시장화를 촉진하는 남북경협 보내기 미리보기 임시저장 내게쓰기 접기/펴기 새창으로 쓰기 첨부파일','2017-09-01','','','',1,32,'2017-09-01 00:00:00','2017-09-01 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','임을출 교수 국가안보실 정책자문위원회 위원으로 위촉','본 포럼 이사로 활동중인 경남대 극동문제연구소 임 을출 교수께서 국가안보실 북한부문 자문위원으로 위촉되셨네요. 축하드립니다. [보도자료] 국가안보실 정책자문위원회 제1차 회의 개최 ㅇ 국가안보실은 ｢국가안보실 정책자','본 포럼 이사로 활동중인 경남대 극동문제연구소 임 을출 교수께서 국가안보실 북한부문 자문위원으로 위촉되셨네요. 축하드립니다. [보도자료] 국가안보실 정책자문위원회 제1차 회의 개최 ㅇ 국가안보실은 ｢국가안보실 정책자문위원회｣를 구성하여 제1차 회의를 7.21.(금) 11:00 개최할 예정이다. - 이번 회의는 국가안보실장 주재로, 외교, 안보, 통일, 국방 분야에 있어 학식과 경험이 풍부한 전문가들과 주요 정책 현안에 대한 의견수렴의 기회를 갖는다. ㅇ 국가안보실은 새 정부 출범 이후 새롭게 ｢국가안보실 정책자문위원회｣를 구성∙운영함으로써, 다양한 전문가들과의 소통을 확대하고 정책적인 공감대를 강화해 나갈 예정이다. - 정책자문위원으로 총 15명의 자문위원을 위촉할 계획이며, 정기적으로 또는 주요 계기시마다 위원회를 개최하여 다양한 의견을 청취해 나갈 것이다. /끝/ ※ 문의 : 안보전략비서관실 (02-770-7322) ※ 붙임 : ｢국가안보실 정책자문위원회｣ 위촉위원 명단 【 국가안보실 정책자문위원회 위촉위원 】 ■ 국제안보 - 김열수 성신여자대학교 국제정치학과 교수 - 조성렬 국가안보전략연구원 책임연구위원 - 김준형 한동대학교 국제어문학부 교수 ■ 통일 - 김연철 인제대학교 통일학부 교수 - 김창수 코리아연구원 원장 ■ 북한 - 고유환 동국대학교 북한학과 교수 - 임을출 경남대학교 극동문제연구소 교수 *미국 - 최 강 아산정책연구원 부원장 - 박인휘 이화여자대학교 국제학부 교수 ■중국 - 김흥규 아주대학교 정치외교학과 교수 - 황재호 한국외국어대학교 국제학부 교수 ■ 일본 - 양기호 성공회대학교 일본학과 교수 - 조세영 동서대학교 국제학부 교수','2017-07-21','','','',1,31,'2017-07-21 00:00:00','2017-07-21 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','본 포럼의 53차 조찬간담회(9월 28일 수요일)에서 "새로운 가치, 실행!"이라는 주제로 발표를 해주신 송희경의원님의 전자신문 기고입니다.','본 포럼의 53차 조찬간담회(9월 28일 수요일)에서 "새로운 가치, 실행!"이라는 주제로 발표를 해주신 송희경의원님의 소식입니다. 이하 메일 전문입니다. ---------------------------------','본 포럼의 53차 조찬간담회(9월 28일 수요일)에서 "새로운 가치, 실행!"이라는 주제로 발표를 해주신 송희경의원님의 소식입니다. 이하 메일 전문입니다. ----------------------------------------------------------------------------------------------------- 국회 4차산업혁명포럼 공동대표 자유한국당 송희경 의원입니다. 올해 하계 다보스포럼이 중국 다롄에서 지난 6월 27일부터 사흘간 ‘4차 산업혁명과 포용 성장 실현’을 주제로 진행되었는데, 저는 지난해 국회를 찾은 클라우스 슈바프 회장과의 인연 덕에 공식 초청 받아 국회를 대표해 개막식에 잠시 다녀왔었습니다. 참관기를 전자신문에 기고했는데 오늘자(7.4)로 보도되어 관련 내용 함께 나눕니다. 잠시 일독하여 주시면 고맙겠습니다. 그리고, 오는 7월 12일부터 국회 4차산업혁명포럼에서 개최하는 ‘퓨처스아카데미 시즌2’가 본격적으로 오픈합니다. 많은 관심과 참여 기울여 주세요. 무더위, 태풍속 건강 챙기시길 바랍니다.','2017-07-04','','크기변환_20170704_2017_하계_다포스포럼을_다녀와서_전자신문_027면_101054.jpg [352KB]','',1,30,'2017-07-04 00:00:00','2017-07-04 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','제3기 통일ICT전문가교육 입학식 개최','제3기 통일ICT전문가교육과정 입학식이 지난 6월29일(목요일) 한국정보통신공사협회 13층 대회의실에서 개최되었습니다. 본포럼의 회장이신 석호익회장님을 비롯하여 제1기 원우회장이신 시스텍전기통신의 전진우회장님, 제2','제3기 통일ICT전문가교육과정 입학식이 지난 6월29일(목요일) 한국정보통신공사협회 13층 대회의실에서 개최되었습니다. 본포럼의 회장이신 석호익회장님을 비롯하여 제1기 원우회장이신 시스텍전기통신의 전진우회장님, 제2기 원우회장이신 SJ테크의 유창근 회장님 및 많은 원우회원분들께서 참석하여 주셨습니다. 많은분들의 관심과 참여덕분에 성대하게 치뤄질 수 있었습니다. 제3기 통일ICT전문가교육은 9월7일까지 매주 목요일 저녁7시부터 9시까지 2시간동안 진행됩니다. 감사합니다','2017-07-04','','952a4273.jpg [7727KB]','',1,29,'2017-07-04 00:00:00','2017-07-04 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','전자신문[미래포럼]전상권 박사/아주대겸임교수 "정보화운동 성공을 코딩문화운동으로 계승하자"','본 포럼 회원님이신 전상권 아주대 겸임교수님께서 5월 17일 수요일자 전자신문 [미래포럼]에 기고하신 글입니다. [전자신문 2017.05.17] [미래포럼] 전상권 박사/아주대 겸임교수 "정보화운동 성공을 코딩문화운','본 포럼 회원님이신 전상권 아주대 겸임교수님께서 5월 17일 수요일자 전자신문 [미래포럼]에 기고하신 글입니다. [전자신문 2017.05.17] [미래포럼] 전상권 박사/아주대 겸임교수 "정보화운동 성공을 코딩문화운동으로 계승하자" 원문 기사보기 : http://www.etnews.com/20170516000295 이제 대통령 선거 결과 새로 선출된 리더 중심으로 국론을 결집시킬 때다. 새로운 대통령과 집권당은 대한민국을 대내외로 당당하게 대표할 수 있도록 국민 통합과 국가 발전에 솔선수범해야 한다. 이와 함께 이번 기회에 나날이 빠르게 변화하는 세계 흐름에 대응하고 국가 경쟁력을 강화하기 위해 과거의 정보화운동 같은 국민 참여 운동도 동시에 추진, 어려운 국정을 슬기롭게 이겨 나갔으면 한다. 구한말 고종이 등극한 1863년에 영국에선 지하철을 개통하고 잠수함을 만들었지만 우리나라는 1974년에 처음 지하철이 개통됐다. 미국에선 1878년 세계 최초로 교환기가 설치됐지만 우리나라는 1981년이 돼서야 자체 개발했다. 필자의 학창 시절에 매매가 가능하던 백색 전화기가 웬만한 집 한 채 값을 뛰어넘던 기억이 있다. 이렇듯 우리의 1, 2차 산업화는 거의 100년 이상 선진국에 뒤처진 것이 사실이다. ''산업화는 뒤졌지만 정보화는 앞서가자''라는 기치를 내세워 정보화운동을 전략 차원에서 1990년대에 추진했다. 그 결과 3차 산업혁명 시대에 우리나라는 세계 최고 수준의 정보화 인프라를 구축했다. 이 인프라에 기반을 두고 국민 생활 향상과 경제 성장을 위한 정보화 관련 산업 고도화와 발전을 이뤘다. 국제전기통신연합 16 (ITU) 정보화 발전 지수에서 세계 1위로 평가받았고, 유엔이 실시하는 전자정부 평가에서도 2010년 이후 항상 최상위권을 유지하고 있다. 국가 투명성 등을 평가하는 경제협력개발기구(OECD) 공공 데이터 개방 지수에서도 세계 1위를 달성하는 등 우리나라 정보화의 우수성이 세계에서 인정받고 있다. 지난해 우리나라 정보통신기술(ICT) 수출액은 1625억달러로 중국·미국에 이어 세계 3위였다. 전체 무역 수지 흑자의 80% 가까이 ICT가 기여하는 등 정보화 강국으로서 면모를 갖추게 된 것이 국가 차원의 노력 덕분이다. 그러나 3차 산업혁명 시대가 저물고 광풍처럼 다가오고 있는 4차 산업혁명 시대를 맞이하는 와중에 지난해 우리나라의 준비 수준이 139개 국가 가운데 25위라고 한다. 싱가포르(2위), 일본(12위), 대만(16위) 등 아시아권에서도 밀리고 있다. 특히 노동 시장의 유연성 부문은 필리핀(82위)보다도 낮다. 비록 새 정부가 4차 산업혁명 관련 정책 강화를 공약하고 있지만 사회 전반에 걸친 체질과 인식의 근본 변화가 없이는 거대한 변혁에 올바로 대응하기가 어렵다. 그래서 4차 산업혁명 시대를 제대로 대응하기 위한 국민 공감대 조성과 실천 방안으로 ''정보화 운동 성공 경험을 코딩 문화 운동으로 계승 확대시킬 것''을 제안한다. 필자는 즐겁고 다양한 놀이를 포함한 코딩 문화가 사회 전반에 확산되면 소프트웨어(SW) 의무 교육을 빌미로 부유층 중심의 코딩 사교육 왜곡 현상과 같은 여러 부작용이 해소될 것으로 본다. 고령화, 청소년 자살 등과 같은 우리 사회의 근본 문제를 일거에 해결할 수 있다고 믿는다. 우리나라 정보화 운동에 직접 영향을 미친 미래학자 앨빈 토플러는 2001년 당시 김대중 대통령에게 조언했다. 그는 “한국 교육은 21세기의 유연한 방식보다 사라져 가는 산업 체제 시스템에 맞도록 짜인 어긋난 방법을 고수하고 있다”고 지적했다. 그러면서 “학생들이 어느 곳에서든 홀로 독립해서 혁신 생각을 할 수 있는 능력을 배양, 새로운 환경에 적응할 수 있는 교육의 본질 문제를 다뤄야 한다”고 했다. 이런 관점에서 지금의 4차 산업혁명 시대에서 반드시 필요한 창의 인재를 기르기 위해서는 어릴 때부터 코딩 능력을 적극 배양해야 한다. 그 이유는 첫째 코딩을 하다 보면 창의력이 길러지고 사고력이 깊어지는 매우 좋은 방법이기 때문이다. 둘째 반복되는 디버깅 과정에서 인내심을 배우고 문제를 극복하기 위해 소통 능력이 커지는 것을 경험할 수 있다. 물론 그러기 위해선 도전 자세도 필요하지만 오히려 남을 배려하는 정신을 더 함양하게 된다. 더욱이 이번 정권은 미래 인재상을 ''질문 잘하는 사람, 상상력·창의력과 문제 해결 능력을 종합해서 갖춘 자''라는 인식은 필자의 견해와 동일하다. SW를 단순히 코딩을 교육하는 것이 아니라 문제 해결을 위한 사고력을 기르는 것임을 강조한 것도 매우 바람직하다. 이번 기회에 SW를 중심으로 하는 코딩 문화 운동에 경력 단절 여성과 어르신들을 적극 참여시킨다면 우리 사회가 더욱 화합되고 4차 산업혁명 시대를 주도하는 대한민국이 될 수 있다고 확신한다. 전상권 박사/아주대 겸임교수 skchun4@gmail.com','2017-05-17','','','',1,28,'2017-05-17 00:00:00','2017-05-17 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','전자신문[보안칼럼] 서재철 한국인터넷진흥원(KISA)수석연구위원','본 포럼 회원님이신 서재철 한국인터넷진흥원(KISA) 수석연구위원님께서 5월17일 수요일자 전자신문 [보안칼럼]에 기고하신 글입니다. [전자신문 2017.05.17] [보안칼럼] 서재철 한국인터넷진흥원(KISA)수석','본 포럼 회원님이신 서재철 한국인터넷진흥원(KISA) 수석연구위원님께서 5월17일 수요일자 전자신문 [보안칼럼]에 기고하신 글입니다. [전자신문 2017.05.17] [보안칼럼] 서재철 한국인터넷진흥원(KISA)수석연구위원 "올 상반기 화두는 ''사물인터넷 시대 사이버 보안''" 원문 기사보기: http://www.etnews.com/20170515000214 올해 상반기를 빛낸 ''CES 2017''의 주요 화두는 ''연결성''이었다. 이번 CES에서는 정보기술(IT)과 자동차·스포츠 등이 융·복합된 자율주행자동차, 스마트홈 411 , 로봇 등 신기술이 공개됐다. 제품 단계에서의 융·복합에만 그치는 게 아니라 자동차와 가전, 컴퓨터, 통신이 한데 어우러진 변화가 일어나는 것이다. 이에 인공지능(AI) 소프트웨어(SW)와 빅데이터 78 라는 데이터베이스(DB)의 결합으로 4차 산업혁명이 목전에 왔음을 실감하게 한다. 또 앞으로는 모바일 결제 등 모든 것이 모바일로 되는 세상이 온다. 사물인터넷 80 (IoT)의 발전으로 모든 사물이 서로 연결된다. 여기에 가상현실 409 (VR)까지 더해져서 상상만 하던 세상이 미래로 다가올 것이다. 그러나 이런 전망 뒤에는 그림자도 있다. 스마트 공장, 무인 자동차, 드론 352 , 로봇 등 산업 제품뿐만 아니라 스마트홈 411 냉난방기·냉장고 등 가전제품과 심장 맥박을 조절하는 심장박동기의 IoT가 오작동을 일으키면 어찌될 것인가. 각종 IoT 기기가 분산서비스거부( DDoS 39 ) 공격으로 중앙 서버를 공격할 가능성도 있다. 그런 만큼 모든 제품에서 ''사이버 보안''의 의미가 중요해진다. 2007년에 개봉한 영화 ''다이하드4''에서 국가에 불만을 품은 전직 국가정보국 요원이 금융, 교통, 보안, 통신 등 국가 기반 시설을 해킹하는 것처럼 현실이 될 수 있다. 포레스터 리서치는 ''2017년에 더욱 고조되는 사이버보안 위협'' 보고서에서 “IoT, 클라우드, BYOD(개인 단말기를 업무에 사용하는 환경) 확산으로 기업 대응 전략이 바뀌게 됐다”면서 “고급 정보를 목표로 유명인 및 일반인 대상의 무작위 랜섬웨어 살포, IP 절도, DDoS, 사생활 침해 등은 수천 개 기업의 파산·매각 등 심각한 결과를 초래할 것”이라고 진단했다. 또 국가 간 충돌로 격상되는 사이버 전쟁이 가능하다. 비욘드트러스트 보안 전문가들은 “각국의 대통령 선거 등 중요 이슈 개입, 개인 정보 탈취 및 협박, 전력망 방해부터 스턱스넷(Stuxnet, 기간시설 파괴 목적의 바이러스)에 이르기까지 우리는 다양한 사이버 공격 양태를 목격해 왔다”면서 “올해에는 국가가 또 다른 국가를 상대로 한 대규모 사이버 공격을 감행하는 사례가 발생할 것”이라는 부정 전망을 제시했다. 이 밖에 접근 권한 단계가 높은 고위층 사용자를 노리는 공격도 증가할 수 있다. 최근 해외 대기업도 보안 위험에 크게 노출됐다. 지난해 어도비 버그는 93건, 마이크로소프트(MS) 감염 사례는 69건, 애플 취약점은 46건 등을 기록했다. 사이버 공격에 대비하기 위해 기업은 일반 정보 보호 규정을 변경해야 한다. 최근 동향에 기반을 두고 문화와 기술, 컴플라이언스(규제 준수) 기준, 비즈니스 우선 순위에 부합하는 정책을 수립해야 한다. 큰 틀에서 보면 정부나 기업이나 개인이나 크게 다르지 않다. 부문별로 맞게 보호 규정을 계속 조정해 나가야 한다. 한국인터넷진흥원(KISA)의 ''보호나라''에서도 여러 대책과 함께 가이드 및 정보를 제공하고 있으며, 관련 신고도 접수하고 있다. 결국 사이버 보안 정책의 목표는 ''사용자가 해야 할 일을 알려 주고, 사용자가 약속한 내용을 그대로 실천하도록 만드는 것''이 돼야만 한다. 서재철 한국인터넷진흥원(KISA) 수석연구위원 sir@kisa.or.kr','2017-05-17','','','',1,27,'2017-05-17 00:00:00','2017-05-17 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','전자신문[ET단상]석호익회장 "ICT전담조직 만들어 미래승부 걸자"','본 포럼 회장님이신 석호익 회장님께서 4월14일 금요일자 전자신문 [ET단상]에 기고하신 글입니다. [전자신문 2017.04.14] [ET단상] 석호익 동북아공동체ICT포럼 회장 "ICT전담조직 만들어 미래승부 걸자','본 포럼 회장님이신 석호익 회장님께서 4월14일 금요일자 전자신문 [ET단상]에 기고하신 글입니다. [전자신문 2017.04.14] [ET단상] 석호익 동북아공동체ICT포럼 회장 "ICT전담조직 만들어 미래승부 걸자" (본문 중) "차기정부는 4차산업혁명에 잘 대처해서 미래를 대비하고 현안문제를 해결해야 한다. 국가의 변화와 혁신을 주도할 ICT전담 부서를 만들어 대한민국의 미래에 승부를 걸어야 한다.... 각 부처에 분산된 ICT기능을 일원화 하고 ICT전담부서가그 컨트롤타워 역할을 해야한다."','2017-04-14','','20170414104843.bmp [25487KB]','',1,26,'2017-04-14 00:00:00','2017-04-14 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','4월 21일 동대문디자인플라자(DDP)에서 2017년 과학·정보통신의 날 기념식 개최','2017년 과학 ·정보통신의 날 기념식이 4 월 21 일(금) 동대문디자인플라자 (DDP)알림 2관 에서 개최됩니다. 많은 관심 부탁드립니다.','2017년 과학 ·정보통신의 날 기념식이 4 월 21 일(금) 동대문디자인플라자 (DDP)알림 2관 에서 개최됩니다. 많은 관심 부탁드립니다.','2017-04-11','','b7d9bb2f6a6989b2d0b55fb73185e3b6_1.jpg [313KB]','',1,25,'2017-04-11 00:00:00','2017-04-11 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','[ 4.15등반대회 신청 ] 4월15(토) 정보산업인 등반대회 참석 희망자 파악','[ 4.15등반대회 신청 ] 4월15(토) 정보산업인 등반대회 참석 희망자 파악 동북아공동체 ICT 포럼에서는 4월15일 개최되는 정보산업인 등반대회에 예년과 같이 본 포럼 명의로 참석하기로 했습니다. 남산 둘레길을','[ 4.15등반대회 신청 ] 4월15(토) 정보산업인 등반대회 참석 희망자 파악 동북아공동체 ICT 포럼에서는 4월15일 개최되는 정보산업인 등반대회에 예년과 같이 본 포럼 명의로 참석하기로 했습니다. 남산 둘레길을 같이 걸으며 건강도 다지고 많은 정보산업인들과 친목을 나눌 수 있는 좋은 기회입니다. 한 팀이 5명이오니 참석을 희망하시는 분은 4.12수요일 오전까지 저에게 연락부탁드립니다. 구교광 부회장 올림 한국정보산업인산악회 창립40주년기념 한마음 등반대회 신청바랍니다. 약 300명이 참가하므로 음식준비를 위해 사전에 꼭 입금하시고 확인해 주시면 대회진행이 순조롭겠습니다. 회원 여러분! 대회 참석여부를 먼저 파악하며 대회준비를 위해 참가비용을 입금해주시고 5명 1팀을 구성해서 신청하시면 좋겠습니다. 그리고 주변 지인분, 가족분 함께 참석 신청해 주시기 바랍니다. [ 신청방법안내 ] 1.일시 : 2017.4.15(토) 09:00 ~ 17:00 2.장소 : 남산둘레길 진입로 소운동장 *) 서울유스호스텔입구 "기억의 터" 계단 위 3.참가비용 : 1인 2만, 1팀5명 10만원 4.입금구좌 : 국민은행 816901-04-243364 조성갑(한정산) # 첨부 : 대회신청서 https://mail.naver.com/read/popup/?nMailId=2071 [ 후원관련안내 ] 1. 후원물품 : 후원물품은 작은 기념품도 감사히 받습니다, 2. 후원구좌 : 하이테크정보세계, 기업한가족통장 "203-045071-04-013" *) 행사대행사 : 하이테크정보, 입금을 원하시면 사전에 연락주세요 *) 후원관련 세금계산서가 필요하시면 도움드립니다. *) 세금계산서가 필요없이 후원하시면 "국민은행 816901-04-243364 조성갑(한정산)" 구좌로 입금하시면 되겠습니다. 재무부회장 연락처 : 박종순 010-7336-2765','2017-04-06','','','',1,24,'2017-04-06 00:00:00','2017-04-06 00:00:00');
