INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','[동정]석호익 통일IT포럼 회장','출처 : http://www.etnews.com/news/telecom/telecom/2754716_1435.html','출처 : http://www.etnews.com/news/telecom/telecom/2754716_1435.html','2013-04-24','','','',1,17,'2013-04-24 00:00:00','2013-04-24 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','통일IT포럼 이상산 부사장, "북한개발자 실력이 더 뛰어나"','출처 : 조선비즈 2011.07.15일자 http://biz.chosun.com/site/data/html_dir/2011/07/15/2011071501347.html 통일IT포럼 이상산 부사장, "북한개발자 실력이','출처 : 조선비즈 2011.07.15일자 http://biz.chosun.com/site/data/html_dir/2011/07/15/2011071501347.html 통일IT포럼 이상산 부사장, "북한개발자 실력이 더 뛰어나" 류현정 기자 dreamshot@chosun.com ▶기자의 다른 기사보기 입력 : 2011.07.15 15:33 ad_random = Math.floor(Math.random()*3+1); if (ad_random == 1){ $(''#art_promotion'').append(" "); } else if (ad_random == 2){ $(''#art_promotion'').append(" "); } else { $(''#art_promotion'').append(" "); } “개발자의 교육 수준이 높고 언어 차이가 없어 북한 개발자를 활용한 아웃소싱의 이점은 매우 큽니다.” 15일 서울 프라자 호텔에서 열린 통일IT포럼 간담회에서 이상산 다산네트웍스 부사장은 ‘남북IT협력 사업현황’을 주제로 한 발표에서 “다산네트웍스는 전 세계 10여개 국가에 업무 아웃소싱을 추진한 경험을 갖고 있다”면서 “인도 고급 개발자는 월 5000달러, 중국 개발자는 월 2000~3000달러인데 반해 중국에서 근무하는 북한 개발자는 월 1500달러 수준”이라고 말했다. 다산네트웍스는 지난 2001년 8월 중국 단동에 개소한 하나프로그람 센터에 근무하는 북한 개발자에 네트워크 장비 관련 개발을 위탁한 바 있다. 국내 기업인 하나비즈닷컴의 자회사인 하나프로그람센터는 북한에서 중국으로 파견한 인력을 활용, 전문적인 소프트웨어 개발 용역 업무를 수행해 왔다. 이 부사장은 하나프로그람센터를 활용한 아웃소싱의 장점으로 ▲ 북한 고급 인력(기사장, 부기사장, 종합실장 등 CTO급)을 활용할 수 있는 점 ▲ 보통 3년 이상 장기 근무자가 많아 업무를 안정적으로 할 수 있었던 점 ▲ 다른 국가 개발 인력보다 인건비용이 낮은 점 등을 꼽았다. 이 부사장은 “애니메이션 및 단순 프로그래밍 분야에서는 즉각 개발업무가 가능했고, 상용 제품의 경우 3~6개월 적응 기간을 거쳐야 개발 업무가 가능했다”고 덧붙였다. 단점으로는 ▲ 하드웨어 기반 기술, 서비스, UI(사용자환경) 등 소프트웨어를 제외한 IT 분야에 대한 이해 부족 ▲ 남북 정치 변수에 따라 인력 활용에 제약을 받는 점 등을 꼽았다. 2009년 7.7 디도스 대란, 2010년 천안함 폭침 사건, 연평도 포격 사건 등 남북 관계에 민감한 이슈가 터진 후 하나프로그람센터 운영은 사실상 중단됐다. 이 부사장은 “2000년대 ‘단번 도약 전략’을 내세운 북한이 영재들을 컴퓨터 소프트웨어 개발에 집중배치해왔고 그 결과 북한 개발자의 수학적 이해, 인공지능 개발, 기반 기술 이해 수준은 한국 개발자의 수준보다 더 높다”고 평가했다. 그는 “그러나 북한에는 여전히 (서버,네트워크 등) 하드웨어 인프라가 부족하기 때문에 하드웨어에 대한 이해가 낮고 똑똑한 개발자들이라도 서비스와 UI의 경우에는 아예 개념조차 잡지 못하는 경우가 많았다”고 덧붙였다. 석호익 통일IT포럼 부회장은 “최근 남북 관계에 어려움이 있었지만, 물이 흐르듯 순리대로 풀어가야 한다”면서 “앞으로 통일IT포럼이 북한의 변화에 대비하고 남북한 IT교류 활성화에 중요한 역할을 할 수 있도록 하겠다”고 말했다. 통일IT포럼은 2000년 9월 정보화를 통한 남북간 경제협력을 목적으로 설립됐으며 이번 간담회에는 석호익 KT 부회장을 비롯해 박찬모 전 포항공대 총장(초대 IT포럼 회장) 등을 비롯해 방송통신위원회, KT, 삼성전자 관계자 등 기업·학계·정책담당자 100명이 참가했다.','2011-07-25','','','',1,16,'2011-07-25 00:00:00','2011-07-25 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','이상산 “북한 IT인력 비용 저렴하고 실력 우수”','출처 : 전자신문 2011.07.18일자 http://www.etnews.com/201107150113 이상산 “북한 IT인력 비용 저렴하고 실력 우수” // "); //]]> 지면일자 2011.07.18 방은주기자','출처 : 전자신문 2011.07.18일자 http://www.etnews.com/201107150113 이상산 “북한 IT인력 비용 저렴하고 실력 우수” // "); //]]> 지면일자 2011.07.18 방은주기자 ejbang@etnews.com ▶ 기자의 다른 기사 보기 “북한(평양)의 소프트웨어 개발자 월 평균 비용은 500달러에 불과합니다. 비용이 적고 실력이 우수한 북한 소프트웨어 개발자들을 활용하는 방법을 적극 찾아야 합니다.” 이상산 다산네트웍스 부사장은 통일IT포럼(회장 석호익 KT 부회장)이 15일 서울 프라자호텔에서 개최한 조찬간담회에서 이같이 밝히며 “북한은 초등학교 때부터 영재들을 대상으로 IT교육을 실시하고 있으며 김일성종합대학을 비롯해 김책종합대학·평성리과대 등에서 국가적으로 우수 IT 인력을 양성하고 있다”고 말했다. 그에 따르면 개발자 한명당 한달 비용인 ‘MM코스트’가 북한(평양)은 500달러, 중국(상하이) 3000달러, 베트남(하노이) 1200달러, 인도(아리슨트社) 5000달러에 달한다. 북한은 인도의 10% 수준에 불과하다. 지난 2001년 다산이 북한과 접경지역인 중국 단둥에 북한 IT 인력을 활용한 하나프로그램센터 설립 당시 초대 총괄매니저를 지낸 그는 “북한이 ‘단번도약’과 ‘강성대국 건설’을 위해 2000년 초부터 IT 분야에 국가적 관심과 역량을 집중하고 있다”면서 “7·7디도스와 천안함 폭침으로 남북경협이 중단됐는데 이대로 가면 지난 10년간 축적한 신뢰와 남북 IT경협 기반이 붕괴될 것”이라고 우려했다. 이 부사장은 한국은 △사업에 필요한 개발자 수 부족 △필요한 개발력을 가진 개발자도 부족 △개발자 인건비가 급상승 △고용 탄력성 부족 등 4가지 SW 인력 딜레마에 빠져 있다고 덧붙였다. -->인공지능과 정보처리, 일부 기반기술은 북한이 남한을 능가한다고 강조한 이 부사장은 “일부에서 해킹 기술을 우리가 가르쳐줬다고 하는데 솔직히 우리가 그들에게서 배운 점이 많았을 정도로 북한은 소프트웨어 실력이 우수하다”면서 “다만 그들은 서비스가 없어 하드웨어 기반은 우리가 월등히 낫다”고 말했다. 포럼에는 석호익 회장을 비롯해 박찬모 전 포항공대 총장, 라봉하 방통위 국제협력관, 조현정 비트컴퓨터 회장 등 100여명이 참석했다. 방은주기자 ejbang@etnews.com','2011-07-25','','','',1,15,'2011-07-25 00:00:00','2011-07-25 00:00:00');
