INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','최성교수- 북한 개방과 ‘新 동양평화론’ (전자신문)','최성 교수 북한 개방과 ‘新 동양평화론’ (전자신문) 바로가기','최성 교수 북한 개방과 ‘新 동양평화론’ (전자신문) 바로가기','2010-08-23','','','',1,10,'2010-08-23 00:00:00','2010-08-23 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','조현정 비트컴퓨터 회장(디지털타임즈 10.02.08기사)','세계적인 고령화 추세와 IT기술 발전으로 u헬스케어 산업이 각광을 받고 있다. 정부차원에서 u헬스케어를 위한 법제도 개선과 시범 사업 실시 등 노력을 기울이고 있으며 기업들도 u헬스케어를 신 성장 사업으로 추진하고 ','세계적인 고령화 추세와 IT기술 발전으로 u헬스케어 산업이 각광을 받고 있다. 정부차원에서 u헬스케어를 위한 법제도 개선과 시범 사업 실시 등 노력을 기울이고 있으며 기업들도 u헬스케어를 신 성장 사업으로 추진하고 있다. 이런 움직임 속에서 주목을 받고 있는 곳이 비트컴퓨터다. 의료정보와 u헬스케어 부분에서 기술력과 노하우를 보유하고 있는 기업이다. 특히 비트컴퓨터는 조현정 회장이 벤처 1호로 창업한 이후 27년 간 많은 기업들이 사라지는 동안 의료IT 부문에 한 우물을 파며 꾸준히 실적을 쌓아왔다. 또 비트컴퓨터 교육센터를 통해 오랜 기간 동안 소프트웨어(SW) 개발 전문인력을 양성, IT융합 시대를 준비해 왔다. 조현정 비트컴퓨터 회장으로부터 회사의 사업방향과 u헬스케어 산업 전망 그리고 IT융합 시대를 위한 인재 양성 방향에 대해 들어봤다. 대담=장윤옥 IT정보화부 부장 -비트컴퓨터는 벤처1호 기업으로서 자부심이 큰만큼 어깨도 무거운데 올해 사업방향을 어떻게 잡고 있나. 지금까지 비트컴퓨터는 27년 간 생존을 위한 노력을 해 왔다면 앞으로는 사업의 질적인 문제에 관심을 가질 때라고 생각한다. 지금까지 닦은 기반으로 바탕으로 질적인 성장에 힘을 기울일 예정이다. 의료정보 분야도 세부적으로 들어가면 매우 분야가 다양하다. 지금까지 비트컴퓨터는 그 세부적인 분야에 대해 기술과 노하우를 축적해 왔고 이를 기반으로 앞으로 성장해 나갈 것이다. - 의료정보 분야에서 유망한 분야를 꼽는다면. 원격진료를 일부 허용하는 의료법 개정안이 4월 경 국회에 제출될 것으로 알고 있다. 의료법 개정안 논의가 본격화되면 의료환경이 많이 바뀔 것이다. 현행 의료법은 의사와 환자가 대면하지 않으면 진료를 인정하지 않는다. 하지만 진료에는 리얼타임으로 계속 체크하는 것이 필요한 부분이 있다. 고혈압 환자의 경우 아침에 혈압이 높고 오후에는 낮게 나오는 데 이같은 추이를 파악해 관리하면 더욱 적절한 처방을 할 수 있다. 원격 시스템이 이같은 진료에 적용되면 생활을 바꿔줄 것이다. 산업도 이에 맞춰 변할 것이다. 비트컴퓨터는 그동안 국내에서 시행된 u헬스케어 레퍼런스 중 절반 이상을 수행해 이 부문에서 경쟁력이 크다고 생각한다. -u헬스케어 서비스가 본격화되면 전문기업보다 대기업 이 더욱 경쟁력을 가질 수도 있다고 생각되는데 전문기업의 위상과 가능성에 대해서는 어떻게 보나. 그동안 비트컴퓨터가 의료정보화 분야에서 사업을 해왔지만 더 많은 업체들이 시장에 참여해 크기를 더 키워야 한다고 생각한다. 하지만 중심은 비트컴퓨터처럼 꾸준히 관련 사업을 해왔던 기업들이 될 것이다. 비트컴퓨터가 처음 의료정보화 사업을 시작할 당시 아예 의료IT라는 분야가 없었다. 그럼에도 불구하고 27년동안 한 우물만 파 왔다. 대기업은 그동안 끊임없이 시장에 참여했지만 사업을 계속 끌고 가지 못했다. 집중적인 투자를 하다가도 성과가 없으면 한 순간에 관련 부서가 사라진다. 의료IT 분야는 신뢰가 굉장히 중요하다. 우리는 이거 아니면 안 된다는 생각으로 사업을 해왔다. 그동안 쌓은 노하우는 자본력만으로 쉽게 얻을 수 있는 것이 아니다. 그러므로 u헬스케어 사업 중심은 전문기업들이 될 것이라고 생각한다. -최근 의료정보 업체들이 해외에서 성과를 거두고 있는데 해외 시장전망을 어떻게 보고 있고 어떤 분야에 기회가 있다고 생각하나. 최근 해외시장에서는 의료영상정보솔루션( PACS ) 분야가 괄목할만한 성과를 거두고 있다. PACS가 해외에서 성공하고 있는 것은 세계 표준에 맞춰져 있고 패키지성 제품이어서 세계 어디든 쉽게 도입해 쓸 수 있기 때문이다. 비트컴퓨터도 태국의 15개 병원에 제품을 공급했고 현대종합상사와 함께 카자흐스탄 에 578만달러 규모의 `통합디지털병원솔루션`을 수출하게 됐다. 특히 카자흐스탄의 사업 수주전에는 오라클, 마이크로소프트 등 글로벌 기업들이 참여했지만 비트컴퓨터와 현대종합상사가 사업을 따내 의미가 있다고 생각한다. 이를 바탕으로 카자흐스탄의 또 다른 병원사업을 수주하기 위해 프리젠테이션(PT)을 하고 있어 결과에 기대를 걸고 있다. 이밖에도 주요 종합상사들과 MOU를 체결, 디지털병원솔루션을 수출하는 방안을 논의하고 있다. 하드웨어 제품만을 취급하던 종합상사들이 최근 소프트웨어를 유망품목으로 꼽고 있어 해외에서 더욱 많은 성과가 나올 것으로 본다. -비트컴퓨터의 u헬스케어 사업에 대해 좀 더 자세히 알려달라. 구체적으로 어떤 준비를 하고 있나. 비트의 u헬스케어 사업은 올해가 흑자 원년이 될 것이다. 교정 시설에 구축한 u헬스케어 시스템이 호평을 받고 있고 독도의 u헬스케어 시스템이나 전남 신안군의 u헬스케어 시스템 등 의미 있는 사이트가 적지 않다. 최근에는 서울시가 의료취약계층을 위해 u헬스케어 구축했는데 도시형 u헬스케어 사업으로 의미가 있다고 보고 있다. 개인 대상으로는 KT와 IPTV를 통한 u헬스케어 사업을 진행하고 있다. IPTV를 통해 개인 건강 관리를 해주는 것으로 이용자가 한번만 자신의 건강상태를 설정해 놓으면 식단을 짜주기도 하고 건강에 필요한 맞춤 형 정보를 제공해 준다. IPTV 사용자가 늘면 늘수록 이를 통한 u헬스케어 사업도 성장할 것으로 기대하고 있다. 한국전자통신연구원(ETRI)과 개발하고 있는 스마트워치도 기대하는 분야다. 시계처럼 손목에 차는 u헬스케어 솔루션으로 생체정보를 인식해 관리하고 보호자에게 해당 내용을 전송해준다. 현재 3차 버전을 만드는 중인데 개발이 마무리되면 독거노인 등의 건강을 체크해주는 좋은 솔루션이 될 것으로 보인다. 건강에 이상이 생기면 바로 의료기관에 전달할 수도 있고 병원이 만성질환자에게 대여해 정기적으로 건강을 체크할 수도 있다. - 비트컴퓨터가 투자한 왕십리 민자역사인 비트플렉스가 성공을 거두고 있다고 들었다. 비트플렉스와 관련한 계획은 없나. 왕십리 비트플렉스는 비트컴퓨터의 사업 구조를 바꿔줄 것이다. 앞으로 비트컴퓨터 사업 부서에서 나오는 돈은 사업부에서 쓰고 왕십리 비트플렉스에서 향후 나오는 자금은 연구개발(R&D)에 활용해 비트컴퓨터가 성장할 수 있도록 할 계획이다. - 특히 IT교육 분야에 많은 관심을 갖고 있는 것으로 아는데. 비트교육센터는 수익 창출이 목적이 아니고 내가 사회에 공헌하는 방법이다. 사회공헌의 방법은 여러 가지가 있는데 그 중 전문가를 양성해 몸담고 있는 생태계에 기여하는 것도 사회공헌의 방법의 방법이라고 생각한다. IT업계는 심각한 인재난에 직면해 있다. 이런 문제를 타개하기 위해 인력양성에 힘써왔고 지금까지 8100명의 IT전문가를 배출했다. 비트는 배출한 인력에 대해 평생 취업률 100%라고 말한다. 3~4년 전 수료했더라도 찾아오면 또 취업을 시켜주고 만약 그 사이에 많이 역량이 떨어졌다고 여겨지면 무료로 재교육을 한다. 최근에는 기업들이 맞춤형 교육을 많이 한다. 하이닉스와의 협력은 맞춤형 교육의 대표적인 성공사례다. 하이닉스와 공동으로 교육과정을 개설, 임베디드SW 개발자 10명을 충원하기로 하고 공고를 냈다. 처음에는 과연 우수한 인력들이 많이 지원을 해줄지 걱정했는데 결과 는 49대 1이었다. 이같은 사례를 바탕으로 정부부처와 교육 모델을 확대하는 방안을 준비하고 있다. - 앞으로 IT인력 양성이 어떤 방향으로 나아가야 한다고 생각하는지 비트컴퓨터가 SW 전체 매출과 개발자 숫자를 고려해 교육센터를 통해 교육시킨 8100명의 산업 기여도를 조사해 보니 약 1조8000억원에 이르렀다. SW 개발자가 1인당 2.3억원 이상 국가 경제에 기여하고 있는 것이다. 청년 인턴제 들어갈 돈으로 사람을 키워서 SW강국을 만드는 것이 훨씬 효과적이라고 생각한다. SW 인력을 2~3명 고용 하는 것은 단순히 사람을 2~3명 더 뽑는 것이 아니라 제조업으로 생각하면 생산라인을 늘리는 것이다. 이에 따라 생산 서비스, 관리 인력에 대한 고용도 추가적으로 늘리는 효과가 발생한다. SW 개발에 젊은이들이 지원을 안 한다고 하는데 희망을 주지 않아서 생긴 문제다. 일을 하는 것에 대한 대가가 있다고 하면 온다. 정부가 IT융합을 강조하는데 IT융합의 핵심은 SW다. 인력을 키우지 않으면 안 된다. 일각에서는 인도 SW개발 인력을 데려다 쓰면 된다고 하지만 이렇게 되면 IT융합 산업은 10년을 장담 못한다. 고급인력을 키워야 한다. 정부에 5년 내에 30만명의 SW개발자를 키우자고 건의했다. -IT특별보좌관에 거론 되는 등 외도설도 꾸준히 나오고 있다. IT특별보좌관의 제안이 있기는 했다. 하지만 사양했다. 나보다 잘 할 수 있는 사람이 많고 기업가는 사업을 열심히 하는 것이 나라에 봉사하는 것이라고 생각했기 때문이다. 앞으로도 비트컴퓨터와 후배양성에 힘을 기울일 계획이다. 정리=강진규 기자 kjk@','2010-02-08','','','',1,9,'2010-02-08 00:00:00','2010-02-08 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','통합KT 대외부문장에 석호익씨','KT와 KTF가 합병 하는 통합KT의 대외부문장에 석호익 김앤장법률사무소 고문(전 정보통신 연구원장)이 내정됐다. 통합KT의 신설 조직인 대외부문은 기존 대외협력실과 홍보실을 통합, 대외 협력 업무 전반을 총괄하게 ','KT와 KTF가 합병 하는 통합KT의 대외부문장에 석호익 김앤장법률사무소 고문(전 정보통신 연구원장)이 내정됐다. 통합KT의 신설 조직인 대외부문은 기존 대외협력실과 홍보실을 통합, 대외 협력 업무 전반을 총괄하게 된다. 석 내정자는 부회장(혹은 사장)으로 대외부문장을 맡을 것으로 예상된다. 이와 관련, KT는 오는 20일 열리는 이사회 에서 직제 개편에 따른 인사를 확정할 예정이다. 석 내정자는 지난 1977년 행정고시 21회로 공직에 입문한 이후 옛 정보통신부 정보화기획실장과 정책홍보관리실장을 거쳐 지난 2006년 정보통신연구원(KISDI) 8대 원장 을 역임했다. 이후 2008년 한나라당 공천을 받아 18대 국회의원 선거에 출마한 바 있으며 현재 통일IT포럼 회장을 맡고 있다. 통합KT 개인고객부문장과 관련, KT는 전·현직 KT 인사 4명을 후보군으로 압축하고 최종 인선 작업에 착수한 것으로 확인됐다. 김우식 KT파워텔 사장을 비롯해 전·현직 KT 인사의 면접 도 일단락한 것으로 알려졌다. KT 주변에서는 김 사장이 유력한 가운데 다른 후보들에 대한 적합성도 여전히 검토 중인 것으로 알려졌다. KT는 “개인고객부문장에 특정 인사를 내정한 단계는 아니다”며 “후보를 대상으로 검토 중”이라고 소개했다. 김원배기자 adolfkim@etnews.co.kr','2009-08-12','','','',1,8,'2009-08-12 00:00:00','2009-08-12 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','문행규 상임이사 ''과학기술자•공학도를 경영도사로 만드는 40가지 노하우 종합기술경영'' 출간','과학기술자. 공학도를 경영도사로 만드는 40가지 노하우 종합기술경영 (The)Comprehensive Technical Management 저자 문행규, 출판사 MSI, 판매가격 15,000 원, 문의: 02-538','과학기술자. 공학도를 경영도사로 만드는 40가지 노하우 종합기술경영 (The)Comprehensive Technical Management 저자 문행규, 출판사 MSI, 판매가격 15,000 원, 문의: 02-538-4800 책소개 과학기술자.공학도가 알아야 할 경영, 경제, 인문사회, 예술, 철학지식은 무엇일까? 토목, 건축, 기계, 전기, 정보통신, 소방, 환경, 안전관리, 정보처리기술자들이 설계, 시공, 감리현장에서 부딪치는 문제들을 해결하는데 필요한 기법들을 파헤친다. 기획, 관리, 연구, 마케팅, 기술거래, 기술가치평가분야의 문제들도 사례를 들어 해설 함으로써 기술경영의 노하우를 전수하였다. 과학자, 기술자, 공학도에게 인생을 뒤바꿔 줄 마법같은 법칙으로 개인에게 행복한 삶과 물질적인 성공을 동시에 안겨주었다. ''종합기술경영''은 우리나라의 과학기술자.공학도가 수세기 동안 변호사, 의사 등 타 전문직에 비해 열악한 환경에서 고전해 왔던 장벽을 뛰어넘은 극히 소수의 과학기술자들만이 알고 있었 던''부와 성공의 비밀''을 알려준다. 과학기술자의 내면에 잠재되어 있는 이 비밀의 힘을 이용하면 좀 더 업그레이드된 인생을 살 수 있을 거라고 조언하며 돈, 인간관계, 정보, 안전, 환경, 세계, 윤리 등의 분야로 나누어 각각 의 위대한 비밀을 파헤친다. 여기에는 ''TQC'', ''관리회계'', ''의사결정론'', ''리스크관리'',''인간관계관리'', ''리더십'', ''ISO''등 기술경영의 비밀을 잘 활용하여 성공한 사례들, 저자가 발견한 손쉬운 방법 및 비결 등을 모두 수록하였다. -> 이 책의 독서포인트! 기술경영의 비밀을 활용하여 명예, 부, 행복을 모두 획득한 과학기술자들의 지혜가 가득 담겨 있는 이 책은 당신의 인생을 180도 바꿔줄 것이다. 저자 소개 - 문행규 기술사 * 1998년 전화국에서 기술부장으로 일하다 미국 AT & T 에 파견되어 네트워크 엔지니어링, 마케팅을 공부하고 기술경영의 비밀을 파헤치겠다고 작심하였다. 한국에 돌아와 정보통신 기술사 자격을 획득하고, KT에서 신규사업부장, 해외기획부장으로 일한 경험과 KT 동경 사무소장, KT Japan 시장을 거치면서 일본 기술사들이 종합기술감리, 경영 지식을 습득하기 위해 ''종합기술감리기술사'' 자격에 도전하는 것을 보고 이 책을 집필하게 되었다. * 자 격 : 정보통신기술사, 국제기술사 (Apec Engineer, EMF Engineer in Information Engineering) * 이 력 - 체신공무원 교육원, 해군종합기술학교 교관, KT 연수원 교수, 동서울대학교 겸임교수 역임 - 일본경제신문, 일본신사회시스템연구소 초빙강사 역임 - 현재 한국정보통신기술사회회장, 한국기술사회 한일교류위원, 한국정보통신대학 정보통신 감리원 강사 * 목 차 - 서문 - 종합기술경영의 내용과 체계 - 경제성관리 - 인적자원관리 - 정보관리 - 안전관리 - 사회환경관리 - 세계화와 국제표준 ISO - 기술자 윤리 - 한반도 평화 * 기술경영의 비밀을 배우면서, 과학기술자.공학도도 원하는 것은 무엇이든 될 수 있고, 얻을 수 있고, 할 수 있다는 점을 알게 되리라. 진실로 웅대한 삶이 자신을 기다린다는 사실 을 알게 되리라.','2009-04-08','','신간도서안내-종합기술경영.hwp [758KB]','',1,7,'2009-04-08 00:00:00','2009-04-08 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','서재진 통일연구원 원장 2월 통일IT포럼 조찬토론회 강연 예정','서재진 통일연구원 원장이 오는 2월24일 프레지던트 호텔에서 열리는 2009 통일IT포럼 조찬 토론회에서 ‘오바마 정부 출범과 남북 관계 전망’이라는 주제로 강연을 펼친다. 서 원장은 전세계가 주목하고 있는 오바마 ','서재진 통일연구원 원장이 오는 2월24일 프레지던트 호텔에서 열리는 2009 통일IT포럼 조찬 토론회에서 ‘오바마 정부 출범과 남북 관계 전망’이라는 주제로 강연을 펼친다. 서 원장은 전세계가 주목하고 있는 오바마 미 대통령의 국제 질서 변화와 이명박 정부의 통일 정책에 대한 심도 있는 전망을 제공할 예정이다. 서 원장은 통일연구원 북한인권센터 소장, 북한연구실장 등을 거쳐 지난해 8월부터 대통령실 정책자문위원화 통일연구원 원장을 맡고 있다. [ 문 의 ] 통일IT포럼사무국 (070) 8233 - 3420','2009-02-19','','','',1,6,'2009-02-19 00:00:00','2009-02-19 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','이현덕 논설주간 ''기자반성문'' 출간','제목 기자 반성문, 지은이 이현덕, 펴낸곳 전자신문사 이현덕 전자신문 전 논설주간이 신문기자의 삶이 오롯이 녹아있는 현장 기록 인 ‘기자 반성문’을 펴냈습니다. 이 책은 전자신문 편집국장과 논설주간을 지낸 저자가 현','제목 기자 반성문, 지은이 이현덕, 펴낸곳 전자신문사 이현덕 전자신문 전 논설주간이 신문기자의 삶이 오롯이 녹아있는 현장 기록 인 ‘기자 반성문’을 펴냈습니다. 이 책은 전자신문 편집국장과 논설주간을 지낸 저자가 현직에서 기자들과 호흡 을 맞춰 신문을 제작하면서 보고 느끼고 겪은 일을 마치 멍석을 역듯이 정리한 아날로그 감성 IT보고서라고 할 수 있습니다. 저자는 이 책에서 자신의 분신같았던 전자신문을 떠나는 애기부터 시작해 편집 국장과 논설주간 시절의 신문제작 과정의 일화, 애환, 아쉬움 등을 마치 한폭의 그림을 그리듯이 애잔하게 정리했습니다. 저자는 신문 제작현장의 경험을 토대로 방송과 통신의 융합시대를 맞아 IT와 미디어, 웹 2.0시대, 급변하는 언론환경 속에서 외국언론 엿보기, 종이 신문의 위기극복 방안 등에 대한 나름의 대안도 제시했습니다. 또한 미디어 대격돌 시대의 기자의 조건과 자세, 칼럼론, 문장론, 대기자, 전문 기자제를 비롯해 노무현 정부와 IT정책, IT관련 부처 장관, IT강국의 어제와 오늘, IT 이슈, 방통위 출범, 통일IT포럼 등 주요 IT포럼 등을 책 갈피에 담았습 니 다. 저자는 지난해 말 인생의 전환점에서 가야산 자락에서 찾은 마음의 평안과 무 심의 세계를 자유로운 필치로 담아낸 에세이집 ‘암자 일기’도 펴냈습니다. 저자는 전자신문에서 논설실장, 편집국장, 논설주간을 역임했으며 한국신문방 송편집인협회 이사와 IT칼럼니스트로 활동하고 있습니다','2009-02-10','','','',1,5,'2009-02-10 00:00:00','2009-02-10 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','[구해우회원 선거사무소 개소식 안내]','[ 개소식 안내 ] ◦ 일시 : 2008년 2월 3일(일) 오후 6시 ◦ 장소 : 서울시 구로구 구로동 98번지 대림오페라 타워 704호 (구로구청사거리 기업은행빌딩) ◦ 연락처 : 02-851-7419 팩스 02-','[ 개소식 안내 ] ◦ 일시 : 2008년 2월 3일(일) 오후 6시 ◦ 장소 : 서울시 구로구 구로동 98번지 대림오페라 타워 704호 (구로구청사거리 기업은행빌딩) ◦ 연락처 : 02-851-7419 팩스 02-851-7420 ※ 자세한 사항은 첨부파일을 참조하시기 바랍니다.','2008-01-24','','open.jpg [172KB]','',1,4,'2008-01-24 00:00:00','2008-01-24 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','2008 IT 산업전망 컨퍼런스 개최','▶ 행사개요 ◀ IT산업전망컨퍼런스는 IT산업 전반에 관한 현 상황과 향후 전망을 파악하기 위해 현시점을 정확히 집어보고, 향후 전망을 살펴 봄으로써 차년도 계획 수립에 도움이 되는 핵심정보 제공의 場 으로 자리매김','▶ 행사개요 ◀ IT산업전망컨퍼런스는 IT산업 전반에 관한 현 상황과 향후 전망을 파악하기 위해 현시점을 정확히 집어보고, 향후 전망을 살펴 봄으로써 차년도 계획 수립에 도움이 되는 핵심정보 제공의 場 으로 자리매김하였습니다. 이번 컨퍼런스는 정보통신 부문별 산업전망에 대해 산업계, 학계, 연구계를 망라한 국내유수의 전문가를 초청하여 지식과 정보를 공유하는 의미있는 자리로 준비하였습니다. ▶ 컨퍼런스 일정 ◀ 개최일자 : 2007년 10월 17일(수) ~ 10월 18일(목) 08:30 ~ 17:40 개최장소 : 잠실롯데호텔 3층 크리스탈볼룸 행사기관 : 주최 - 정보통신부 주관 - 정보통신연구진흥원, 정보통신정책연구원, 한국소프트웨어진흥원, 한국정보사회진흥원, 한국전자통신연구원,정보통신국제협력진흥원, 한국정보통신산업협회 ▶ 등록 안내 ◀ 일반 사전등록 : 9월 12일 ~ 10월 12일 일반 학생 기타 사전등록 7만원 4만원 (학생증 제시 필수) 사전등록은 등록신청 및 입금이 완료된 경우에 한합니다. 현장등록 10만원 7만원 (학생증 제시 필수) ※ 현장등록 시 혼잡이 예상되오니 사전등록을 바랍니다. ※ 발표자료집 및 보고서는 한정 수량 발간되어, 등록자에 한해 배포됩니다. - 발표 자료집은 해당 일별 2권으로 발간되며, 따로 구입하실 수 없습니다. ※ 지불하신 등록비는 환불해 드리지 않사오니 유념하여 주시기 바랍니다. ※ 본 행사는 좌석이 한정되어 있습니다. 등록을 서둘러 주시기 바랍니다. ▶ 프로그램 ◀ ※ 행사 홈페이지( http://www.itconference.or.kr )에 가시면 자세한 프로그램 및 강연요약자료를 보실 수 있습니다. ▶ 문의처 ◀ 정보통신정책연구원 정보통신산업연구실 유선실 책임연구원(570-4333)','2007-10-05','','','',1,3,'2007-10-05 00:00:00','2007-10-05 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','명사초청강연회 및 연구과제 토론회 개최','명사초청강연회 및 연구과제 토론회 초청 모시는 글 안녕하십니까! 대한민국의 미래를 준비하는 “ 미래사회연구포럼 ”은 가을이 완연한 10월에 미래주간행사 의 일환으로 명사 초청강연회와 연구과제 토론회를 개최하고자 합니','명사초청강연회 및 연구과제 토론회 초청 모시는 글 안녕하십니까! 대한민국의 미래를 준비하는 “ 미래사회연구포럼 ”은 가을이 완연한 10월에 미래주간행사 의 일환으로 명사 초청강연회와 연구과제 토론회를 개최하고자 합니다. 우리 미래사회연구포럼 은 사회 각 분야의 미래에 대한 연구와 전망을 하며 불확실하고 급격히 변해가는 미래 사회를 예측하고 이에 대응하여 나아가고 있습니다. 더하여 미래사회연구를 학문으로만 국한시키지 않고 실제 정책에 반영되도록 적극 노력한 결과 국회에서의 입법사례가 늘어나는 등 대한민국의 미래에 대한 다각적인 접근으로 미래사회에 대한 준비를 성실히 해나가고 있습니다. 미래사회연구포럼 은 국가 기반사업의 전략적 활용을 제시하고 정치, 경제, 사회, 문화 영역 등 미래사회 모 든 분야에 대한 총체적인 연구와 진지한 고민으로 미래사회 전 분야의 가치를 높이는 포럼으로 거듭나도록 하겠습니다. 이번 명사 초청 강연회 및 토론회에 여러 정책·자문위원님과 함께 보다 나은 미래사회건설에 관심 있는 분들을 모시고자 하오니 귀한 발걸음을 하시어 자리를 빛내주시길 바랍니다. 2007년 9월 공동의장 : 국회의원 변재일 진영 국회의원 : (가나다순) 강성종, 권선택,김형오, 김희정, 류근찬, 서상기, 서혜석, 심재엽, 오제세, 유승희, 이종걸, 이주호, 정몽준 집행위원장 : 석호익(정보통신정책연구원장) 정책·자문위원 : (가나다순) (유관기관) 배철호, 서남표, 유희열, 이종오, 이호일, 정성철, 최문기, 최석식, 최영락 (업계) 김신배, 김종신, 남용, 남중수, 유재성, 윤종용, 이휘성 (학계) 신민수, 정윤식, 정태명, 황상민 일시 및 장소 o 일 시 : 2007. 10. 15일(월) 14:00~16:30 o 장 소 : 국회 의원회관 1층 회의실 o 주 최 : 미래사회연구포럼 o 주 관 : 정보통신부 o 후 원 : 매일경제신문 진행순서 항 목 시 간 세 부 내 용 구 분 접수 13:30~14:00 등록 개회식 14:00~14:30 사회 김철완 (KISDI협력연구실장) 미래사회연구포럼 개회사 진 영(공동의장) 미래사회연구포럼 환영사 석호익(KISDI원장) 격려 및 축사 : 미래의 대한민국 변재일(공동의장) 축사 유영환 (정보통신부장관) 1부 : 명사 초청강연회 14:30~15:30 강연 “IT와 미래“ 및 질의응답 박영숙 (사)유엔미래포럼 대표 휴 식 2부 : IT와 교육의 현황 파악과 미래의 도출 15:45~16:40 토론 주제 1) 국내외 청소년 컴퓨터 교육 현황 분석 및 비교 2) IT 발전을 위한 올바른 컴퓨터 교육방향 제시 3) 미래형 청소년 IT 교육을 위한 협의체 구성 - 초청 패널 토론 좌장: 변재일 의원 진행: 엄영익 성균관대 교수 행사 종료 참가신청 및 문의 참가를 원하시는 분들께서는 10월 12 일 (금 ) 까지 아래 담당자에게 전화나 이메일로 연락주시기 바랍니다 . 미래사회연구포럼 사무국 hyunju@kisdi.re.kr ☎ 02-570-4026/ 02-570-4331 찾아오시는 길 o 장소 : 국회 의원회관 1층 회의실 o 교통편 -국회순환버스 이용안내(무료) o 운행시간: 월요일~금요일 : 09:00~16:00 (단, 12:20, 12:40 운휴) o 배차간격: 20분 - 지하철 [5호선 여의도역 하차] 3번 출구로 나와 버스 162, 261, 262, 461, 9409번 이용 [1호선 대방역] 360, 363번 버스 이용 [1호선 영등포역] 5615, 5618번 버스 이용 - 버스: 61, 162, 261, 262, 263, 360, 362, 363, 461, 5613, 5615, 5618, 6621, 6623, 6633, 7613, 9409 -주차장이용안내 (국회경내 주차 5부제 실시) o 국회 청사내 주차난을 해소하기 위하여 주차 5부제를 실시하고 있습니다. 많은 협조 부탁드립니다. o 월(1,6), 화(2,7), 수(3,8), 목(4,9), 금(5,0)에 해당되는 날은 청사내 주차가 불가합니다. (둔치주차장은 주차가 가능하오니 이용하시기 바랍니다.) 5부제 통제는 정문등 각 출입문에서 출입이 금지되고 있습니다. 미래사회연구포럼 사무국','2007-10-05','','','',1,2,'2007-10-05 00:00:00','2007-10-05 00:00:00');
INSERT INTO content_items (type,title,summary,body,event_date,event_location,attachment_url,image_url,published,sort_order,created_at,updated_at) VALUES ('resource','연변과기대 15주년 기념 출판회 안내','▣ 일시 : 2007.10.5(금) ▣ 장소 : 장충동 서울클럽 ▣ 참가신청 : 동북아공동체연구회 사무국 02-3461-4242 감사합니다.','▣ 일시 : 2007.10.5(금) ▣ 장소 : 장충동 서울클럽 ▣ 참가신청 : 동북아공동체연구회 사무국 02-3461-4242 감사합니다.','2007-09-20','','','',1,1,'2007-09-20 00:00:00','2007-09-20 00:00:00');
